using UnityEngine;

/// <summary>
/// "Íman de pickups" (item da auditoria de Coleccionáveis): colocado no
/// player, procura periodicamente coleccionáveis próximos com
/// <see cref="PickupBase.canBeMagnetized"/> activo e desloca-os gradualmente
/// para a posição do player. A recolha em si continua a acontecer pelo
/// <c>OnTriggerEnter2D</c> normal de <see cref="PickupBase"/> quando o
/// coleccionável chega suficientemente perto — este script não concede
/// recompensas directamente.
/// </summary>
public class PickupMagnet : MonoBehaviour
{
    [Tooltip("Raio de detecção de coleccionáveis (PickupBase.canBeMagnetized).")]
    public float range = 2.5f;

    [Tooltip("Velocidade com que os coleccionáveis atraídos se aproximam do player (unidades/seg).")]
    public float pullSpeed = 8f;

    [Tooltip("Layer(s) onde procurar coleccionáveis. Vazio (Everything) = todas as layers.")]
    public LayerMask pickupLayer = ~0;

    private const int MaxResults = 16;
    private readonly Collider2D[] _buffer = new Collider2D[MaxResults];

    private void Update()
    {
        // Tarefa #3: o Íman só atrai coleccionáveis enquanto o Instinto
        // "Íman de Sementes" estiver desbloqueado E ligado — sem isto, o
        // íman funcionava sempre, mesmo sem o jogador ter o upgrade.
        if (PlayerProgress.Instance == null || !PlayerProgress.Instance.IsImanDeSementesActive)
            return;

        int count = Physics2D.OverlapCircleNonAlloc(transform.position, range, _buffer, pickupLayer);

        for (int i = 0; i < count; i++)
        {
            var col = _buffer[i];
            if (col == null) continue;

            var pickup = col.GetComponent<PickupBase>();
            if (pickup == null || pickup.Collected || !pickup.canBeMagnetized) continue;

            pickup.transform.position = Vector3.MoveTowards(
                pickup.transform.position,
                transform.position,
                pullSpeed * Time.deltaTime);
        }
    }

    private void OnDrawGizmosSelected()
    {
        Gizmos.color = Color.cyan;
        Gizmos.DrawWireSphere(transform.position, range);
    }
}
